.darma-loader-darma-custom-614 {color: var(--loader-color, #059669);
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid #0000;
   padding: 5px;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000 ) 0 0/20px 20px no-repeat, conic-gradient(from 90deg at 10px 10px,#0000 90deg,currentColor 0) content-box, conic-gradient(from -90deg at 40px 40px,#0000 90deg,currentColor 0) content-box, currentColor;
   filter: blur(4px) contrast(10);
   animation: darma-loader-darma-custom-614-l11 2s infinite;
}
@keyframes darma-loader-darma-custom-614-l11  {
  0% {background-position:0 0}
25% {background-position:100% 0}
50% {background-position:100% 100%}
75% {background-position:0% 100%}
100% {background-position:0% 0}
}

